// Pick the right template based on the (next) attempt number.
// attempt_count in DB is the COUNT OF EMAILS ALREADY SENT.
// Next email being sent will be attempt = attempt_count + 1.
const d = items[0].json;
const nextAttempt = (d.ATTEMPT_COUNT || 1) + 1; // 2 or 3
const missing = (typeof d.MISSING_FIELDS === 'string' ? JSON.parse(d.MISSING_FIELDS) : (d.MISSING_FIELDS || [])).map(f => '  - ' + f).join('
') || '  (none)';
const rawErrs = typeof d.VALIDATION_ERRORS === 'string' ? JSON.parse(d.VALIDATION_ERRORS) : (d.VALIDATION_ERRORS || []);
const errs = rawErrs.map(e => `  - [${e.code}] ${e.detail}`).join('
') || '  (none)';
const extracted = typeof d.EXTRACTED_SO_FAR === 'string' ? JSON.parse(d.EXTRACTED_SO_FAR) : (d.EXTRACTED_SO_FAR || {});
const name = extracted.name || 'there';

let subject, text;
if (nextAttempt === 2) {
  subject = 'Reminder: your exam application is paused — please reply';
  text = `Hi ${name},

This is a friendly reminder. We're still waiting on a few details before we can complete
your exam application. Without these, we won't be able to submit on your behalf.

--- Information we still need ---
${missing}

--- Issues with the documents you sent ---
${errs}

We've sent this reminder because we didn't receive a reply to our earlier email.
Please respond within the next 6 hours.

Reference ID: ${d.USER_ID}

— EasyForm`;
} else {
  subject = 'Final reminder: your exam application will be cancelled';
  text = `Hi ${name},

This is the final reminder. We've reached out twice asking for the items below
and haven't heard back. If we don't receive a reply within the next 6 hours,
your application will be cancelled and the partial data we hold will be discarded.

--- Information we still need ---
${missing}

--- Issues with the documents you sent ---
${errs}

If you do want to continue, simply reply to this email with the missing information
and corrected documents.

Reference ID: ${d.USER_ID}

— EasyForm`;
}

return [{ json: { ...d, _next_attempt: nextAttempt, _email_subject: subject, _email_text: text } }];
